initialization.per_particle_initialization:
variable.lifetime = math.random(1, 3);
variable.age = 0.0;
variable.angle = math.random(0, 360);
variable.elevation = math.random(0, 180);
variable.speed = math.random(2, 8);
variable.vel_x = variable.speed * math.sin(math.radians(variable.elevation)) * math.cos(math.radians(variable.angle));
variable.vel_y = variable.speed * math.cos(math.radians(variable.elevation));
variable.vel_z = variable.speed * math.sin(math.radians(variable.elevation)) * math.sin(math.radians(variable.angle));
variable.size = math.random(0.5, 1.5);
